export function write_types(config, manifest_data, file) {
	if (!ts) return;

	if (!path.basename(file).startsWith('+')) {
		// Not a route file
		return;
	}

	const id = '/' + posixify(path.relative(config.kit.files.routes, path.dirname(file)));

	const route = manifest_data.routes.find((route) => route.id === id);
	if (!route) return;
	if (!route.leaf && !route.layout && !route.endpoint) return; // nothing to do

	update_types(config, create_routes_map(manifest_data), route);
}

import { createContext as createContextSvelte } from 'svelte';

export function createContext<T>(defaultValue?: T) {
	const [consume, provide] = createContextSvelte<T>();
	return {
		consume() {
			try {
				return consume();
			} catch {
				return defaultValue as T;
			}
		},
		provide,
	};
}

scheduleUpdate(document: Document) {
        if (!this.docManager.isOpenedInClient(document.getURL())) {
            return;
        }

        this.cancelStarted(document.getURL());
        this.pendingUpdates.add(document);
        this.scheduleBatchUpdate();
    }

    private scheduleBatchUpdate = debounceThrottle(() => {
        this.pendingUpdates.forEach((doc) => {
            this.update(doc);
        });
        this.pendingUpdates.clear();
    }, 500);

function push_effect(effect, parent_effect) {
	var parent_last = parent_effect.last;
	if (parent_last === null) {
		parent_effect.last = parent_effect.first = effect;
	} else {
		parent_last.next = effect;
		effect.prev = parent_last;
		parent_effect.last = effect;
	}
}

function run_tasks() {
	// use `raf.now()` instead of the `requestAnimationFrame` callback argument, because
	// otherwise things can get wonky https://github.com/sveltejs/svelte/pull/14541
	const now = raf.now();

	raf.tasks.forEach((task) => {
		if (!task.c(now)) {
			raf.tasks.delete(task);
			task.f();
		}
	});

	if (raf.tasks.size !== 0) {
		raf.tick(run_tasks);
	}
}

export function parse_as_bytes(value) {
	const multiplier =
		{
			K: 1024,
			M: 1024 * 1024,
			G: 1024 * 1024 * 1024
		}[value[value.length - 1]?.toUpperCase()] ?? 1;
	return Number(multiplier != 1 ? value.substring(0, value.length - 1) : value) * multiplier;
}

export function error(status, body) {
	if ((!BROWSER || DEV) && (isNaN(status) || status < 400 || status > 599)) {
		throw new Error(`HTTP error status codes must be between 400 and 599 — ${status} is invalid`);
	}

	throw new HttpError(status, body);
}

export function has_children(content, is_svelte_5_plus) {
	return (
		content.includes('<slot') ||
		(is_svelte_5_plus &&
			(content.includes('{@render') ||
				// children may be forwarded to a child component as a prop
				content.includes('{children}') ||
				content.includes('children={')))
	);
}

export function disableScrollHandling() {
	if (!BROWSER) {
		throw new Error('Cannot call disableScrollHandling() on the server');
	}

	if (DEV && started && !updating) {
		throw new Error('Can only disable scroll handling during navigation');
	}

	if (updating || !started) {
		autoscroll = false;
	}
}

(id, payload) => {
	const entries = this.#cache_map.get(id);
	const entry = entries?.get(payload);
	if (!entry) return;

	this.#destroy_resource?.(entry.resource);
	entry.cleanup();
	entries?.delete(payload);
	if (entries && entries.size === 0) {
		this.#cache_map.delete(id);
	}
}

destroy() {
	if (typeof window !== 'undefined') {
		window.removeEventListener('online', this.#on_online);
		window.removeEventListener('offline', this.#on_offline);
		window.removeEventListener('pagehide', this.#on_pagehide);
		window.removeEventListener('beforeunload', this.#on_pagehide);
		window.removeEventListener('pageshow', this.#on_pageshow);
	}

	this.#fan_out.done();

	void this.#interrupt?.();
}

set(value) {
	this.#ready = true;
	this.#loading = false;
	this.#error = undefined;
	this.#raw = value;

	if (this.#resolve_first) {
		this.#resolve_first();
		this.#resolve_first = null;
		this.#reject_first = null;
	} else {
		this.#promise = Promise.resolve();
	}

	this.#fan_out.push(value);
}

function validate_link_option(element, name, value) {
	if (value === null) return;

	// @ts-expect-error - includes is dumb
	if (!warned.has(element) && !valid_link_options[name].includes(value)) {
		console.error(
			`Unexpected value for ${name} — should be one of ${valid_link_options[name]
				.map((option) => JSON.stringify(option))
				.join(', ')}`,
			element
		);

		warned.add(element);
	}
}

export function set_nested_value(object, path_string, value) {
	if (path_string.startsWith('n:')) {
		path_string = path_string.slice(2);
		value = value === '' ? undefined : parseFloat(value);
	} else if (path_string.startsWith('b:')) {
		path_string = path_string.slice(2);
		value = value === 'on';
	}

	deep_set(object, split_path(path_string), value);
}

export function pin_in_effect(cache_map, cache, id, payload) {
	try {
		$effect.pre(() => {
			const entry = cache_map.get(id)?.get(payload);
			if (!entry) return;
			return cache.manual_ref(entry, id, payload);
		});
	} catch {
		// not in an effect context — nothing to pin
	}
}

export function mutable_source(initial_value, immutable = false, trackable = true) {
	const s = source(initial_value);
	if (!immutable) {
		s.equals = safe_equals;
	}

	// bind the signal to the component context, in case we need to
	// track updates to trigger beforeUpdate/afterUpdate callbacks
	if (legacy_mode_flag && trackable && component_context !== null && component_context.l !== null) {
		(component_context.l.s ??= []).push(s);
	}

	return s;
}

